import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"雍和宫","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/index.md","filePath":"religion/yonghegong/index.md","lastUpdated":1784720050000}'),i={name:"religion/yonghegong/index.md"};function r(g,t,d,o,s,h){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="雍和宫" tabindex="-1">雍和宫 <a class="header-anchor" href="#雍和宫" aria-label="Permalink to &quot;雍和宫&quot;">​</a></h1><p><img src="https://plus.unsplash.com/premium_photo-1693236418889-3e0d269c59ad?w=1200&amp;q=80" alt="雍和宫鎏金殿顶与红柱回廊"></p><blockquote><p>&quot;潜邸化禅林，行宫成梵宇——北京最大的藏传佛教寺院，清王朝民族团结与宗教交融的珍贵见证。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>雍和宫位于北京市东城区雍和宫大街28号，坐北朝南，占地约6.6万平方米，是北京城区规模最大的藏传佛教寺院，也是清代内地规格最高的格鲁派（黄教）皇家寺院。整座寺院融汉、满、蒙、藏建筑艺术于一体，殿宇黄瓦红墙、格局严整，香火延续近三百年。</p><p>雍和宫的历史可分为清晰的三个阶段：</p><ul><li><strong>王府时期（1694年）</strong>：清康熙三十三年（1694年）始建为&quot;四爷府&quot;，即皇四子胤禛的府邸；康熙四十八年胤禛晋封和硕雍亲王，府邸升格为&quot;雍亲王府&quot;。</li><li><strong>行宫时期（1725—1735年）</strong>：胤禛即位为雍正帝后，于雍正三年（1725年）将王府升为行宫，赐名&quot;雍和宫&quot;。雍正十三年（1735年）雍正帝驾崩，灵柩曾停于此，主要殿宇改覆黄色琉璃瓦，自此具备皇家宫殿规制。</li><li><strong>寺院时期（1744年至今）</strong>：乾隆九年（1744年）正式改为藏传佛教寺院（喇嘛庙），成为清廷管理藏传佛教事务的重镇，蒙藏高僧驻锡讲经，法事不绝。</li></ul><p>相传乾隆皇帝即诞生于雍亲王府，雍和宫因此享有&quot;龙潜福地&quot;之誉。如今这里既是各族信众礼佛祈福的圣地，也是中外游人凭吊历史、欣赏建筑艺术的胜地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">25元（半价12元）</td></tr><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">约9:00-16:30（11月至次年3月至16:00）</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区雍和宫大街28号</td></tr><tr><td style="text-align:left;"><strong>联系电话</strong></td><td style="text-align:left;">010-64044499</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/5号线雍和宫站，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>建议游览</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，深秋银杏、冬日雪景尤佳</td></tr></tbody></table><h2 id="中轴线六进院落" tabindex="-1">中轴线六进院落 <a class="header-anchor" href="#中轴线六进院落" aria-label="Permalink to &quot;中轴线六进院落&quot;">​</a></h2><p>雍和宫建筑沿中轴线自南向北展开，地势逐进抬高、殿宇逐进宏阔，六进大院层层递进，营造出由尘世步入梵境的庄严序列。</p><table tabindex="0"><thead><tr><th style="text-align:center;">顺序</th><th style="text-align:left;">建筑</th><th style="text-align:left;">主要看点</th><th style="text-align:left;">详情</th></tr></thead><tbody><tr><td style="text-align:center;">一</td><td style="text-align:left;">牌楼院与昭泰门</td><td style="text-align:left;">三座牌楼、砖雕影壁、王府规制遗存</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/pailou-yuan.html">牌楼院与昭泰门</a></td></tr><tr><td style="text-align:center;">二</td><td style="text-align:left;">雍和门（天王殿）</td><td style="text-align:left;">弥勒菩萨、韦驮、四大天王、《喇嘛说》四体碑</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/yonghe-men.html">雍和门</a></td></tr><tr><td style="text-align:center;">三</td><td style="text-align:left;">雍和宫殿（大雄宝殿）</td><td style="text-align:left;">三世佛、十八罗汉、铜铸须弥山</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/yonghe-dadian.html">雍和宫殿</a></td></tr><tr><td style="text-align:center;">四</td><td style="text-align:left;">永佑殿</td><td style="text-align:left;">雍正寝殿与停灵处、三尊白檀佛像</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/yongyou-dian.html">永佑殿</a></td></tr><tr><td style="text-align:center;">五</td><td style="text-align:left;">法轮殿</td><td style="text-align:left;">藏汉合璧、宗喀巴大师像、五百罗汉山</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/falun-dian.html">法轮殿</a></td></tr><tr><td style="text-align:center;">六</td><td style="text-align:left;">万福阁</td><td style="text-align:left;">26米白檀木弥勒大佛、吉尼斯纪录</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/yonghegong/wanfu-ge.html">万福阁</a></td></tr></tbody></table><h2 id="祈福与请香贴士" tabindex="-1">祈福与请香贴士 <a class="header-anchor" href="#祈福与请香贴士" aria-label="Permalink to &quot;祈福与请香贴士&quot;">​</a></h2><p><img src="https://images.unsplash.com/photo-1766872697135-ac4aaee364ec?w=1200&amp;q=80" alt="殿前香炉敬香"></p><ul><li><strong>免费领香</strong>：雍和宫为游客免费提供环保香，无需自带外香；心诚则灵，三支清香即可。</li><li><strong>敬香礼仪</strong>：左手持香举至眉心，躬身三拜后插入香炉；过殿门勿踩踏门槛。</li><li><strong>殿内勿摄</strong>：各殿佛像、唐卡一律禁止拍照；院落内可拍摄，但请避免直拍僧人与礼佛信众。</li><li><strong>保持肃静</strong>：宗教场所请低声缓行，勿以手指点佛像，尊重各民族宗教习俗。</li><li><strong>法物请购</strong>：寺内设有正规法物流通处，开光等事宜请咨询寺院工作人员，勿轻信门外招揽。</li></ul><hr><p><strong>📍 地址</strong>：北京市东城区雍和宫大街28号 <strong>⏱️ 建议游览</strong>：2-3小时 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/">北京宗教建筑</a></p>',18)])])}const x=e(i,[["render",r]]);export{f as __pageData,x as default};
